def solve(arg1: dict) -> list[dict]:
    selector = arg1.get('selector', [])
    if not selector:
        return None

    roles = [
        {'id': 1, 'name': 'Admin'},
        {'id': 2, 'name': 'User'}
    ]

    if 'id' in selector and 'name' in selector:
        return roles
    elif 'id' in selector:
        return [{'id': role['id']} for role in roles]
    elif 'name' in selector:
        return [{'name': role['name']} for role in roles]

    return None
```
